SELECT
    id, employee_no, user_id, dept_id, post_id, leader_id,
    employee_name, gender, phone, email, job_level,
    employment_status, hire_date, create_time, update_time
FROM hr_employee
WHERE is_deleted = 0

    AND id > #{lastId}


    AND dept_id IN

        #{deptId}



    AND (employee_name LIKE CONCAT('%', #{keyword}, '%')
         OR employee_no LIKE CONCAT('%', #{keyword}, '%')
         OR phone LIKE CONCAT('%', #{keyword}, '%'))


    AND employment_status IN

        #{status}



    AND job_level = #{jobLevel}


    AND hire_date >= #{hireDateStart}


    AND hire_date <= #{hireDateEnd}


    AND create_by = #{createBy}

ORDER BY id ASC
LIMIT #{pageSize}
